def extract_google_data(data):
    results = []

    def find_ids(obj):
        if isinstance(obj, list):
            if len(obj) >= 3 and isinstance(obj[2], str) and obj[2].startswith("0x0:0x"):
                results.append(obj[2])
                return

            for item in obj:
                find_ids(item)

    find_ids(data)
    return results

def decode_cid(hex_string):
    try:
        parts = hex_string.split(':')
        hex_cid = parts[1] 
        # Convert Hex to Decimal
        decimal_cid = int(hex_cid, 16)
        return decimal_cid
    except:
        return None

